return $input.all().filter(item => {
  const d = item.json;
  const optOut = (d.OPT_OUT || '').toString().trim();
  const enviou = (d['ENVIOU MSG'] || '').toString().trim().toUpperCase();

  // Pula se ja tem OPT_OUT preenchido
  if (optOut) return false;

  // Pula se ja foi enviado ou esta processando
  if (['FEITO', 'PROCESSANDO', 'ERRO'].includes(enviou)) return false;

  return true;
});

