const COMPANY_KEYWORDS = new Set([
  'contabil', 'contábil', 'contabilidade', 'contabilidades',
  'assessoria', 'assessorias', 'cia', 'ltda', 'eireli',
  'consultoria', 'escritório', 'escritorio', 'soluções', 'solucoes',
  'servicos', 'serviços', 'grupo', 'empresa', 'company', 'digital',
  'imoveis', 'imóveis', 'cartorio', 'cartório', 'precisão', 'precisao',
]);

const COMPANY_ABBREVS = new Set(['ass', 'cont', 'me', 'ss', 'sa']);

const ALL_COMPANY_WORDS = new Set([...COMPANY_KEYWORDS, ...COMPANY_ABBREVS]);

const DEPT_LABELS = new Set([
  'dpto', 'depto', 'departamento', 'dept', 'gestão', 'gestao',
  'financeiro', 'pessoal', 'fiscal', 'rh', 'atendimento', 'contato',
  'marketing',
]);

const GENERIC_LABELS = new Set([...DEPT_LABELS, 'teste', 'test', 'empresa', 'contato', 'atendimento']);

const UFS = new Set([
  'AC','AL','AM','AP','BA','CE','DF','ES','GO','MA','MG','MS','MT',
  'PA','PB','PE','PI','PR','RJ','RN','RO','RR','RS','SC','SE','SP','TO',
]);

const VALID_DDDS = new Set([
  '11','12','13','14','15','16','17','18','19',
  '21','22','24','27','28',
  '31','32','33','34','35','37','38',
  '41','42','43','44','45','46','47','48','49',
  '51','53','54','55',
  '61','62','63','64','65','66','67','68','69',
  '71','73','74','75','77','79',
  '81','82','83','84','85','86','87','88','89',
  '91','92','93','94','95','96','97','98','99',
]);

const PREPOSICOES = new Set(['de', 'da', 'do', 'dos', 'das', 'e']);

function normalizePhone(raw) {
  let phone = String(raw || '').replace(/\D/g, '');
  if (!phone) return { phone: '', valid: false, ddd: '', regiao: '' };
  if (phone.length === 10 || phone.length === 11) phone = '55' + phone;
  if (phone.startsWith('5555') && phone.length >= 14) phone = phone.slice(2);
  const valid = phone.length >= 12 && phone.length <= 13 && phone.startsWith('55');
  if (!valid) return { phone, valid: false, ddd: '', regiao: '' };
  const ddd = phone.substring(2, 4);
  if (!VALID_DDDS.has(ddd)) return { phone, valid: false, ddd: '', regiao: '' };
  return { phone, valid: true, ddd, regiao: ddd };
}

function normalizeSpacedUfs(texto) {
  if (!texto) return texto;
  return texto.replace(/\b([A-Z])\s+([A-Z])\b/g, (m, a, b) => {
    const c = a + b;
    return UFS.has(c) ? c : m;
  });
}

function cleanSeparators(texto) {
  texto = texto.replace(/[+\u00d7\u00f7=]+/g, ' ');
  texto = texto.replace(/^[-\s]+/, '');
  texto = texto.replace(/\s+/g, ' ').trim();
  return texto;
}

function extractWords(texto) {
  return (texto.toLowerCase().match(/[a-z\u00e1\u00e0\u00e2\u00e3\u00e9\u00e8\u00ea\u00ed\u00ef\u00f3\u00f4\u00f5\u00fa\u00fc\u00e7]+/g) || []);
}

function hasCompanyKeyword(texto) {
  const words = new Set(extractWords(texto));
  for (const w of words) { if (ALL_COMPANY_WORDS.has(w)) return true; }
  return false;
}

function isCompanyName(texto) { return hasCompanyKeyword(texto); }

function isPhoneInField(texto) {
  const digits = texto.replace(/\D/g, '');
  return digits.length >= 10 && (texto.trim().startsWith('+') || digits === texto.trim());
}

function isHandle(texto) { return !!(texto && texto.trim().startsWith('@')); }

function isPersonName(texto) {
  if (!texto || !texto.trim()) return false;
  const t = texto.trim();
  if (isPhoneInField(t) || isHandle(t)) return false;
  if (hasCompanyKeyword(t)) return false;
  const lower = t.toLowerCase();
  for (const label of DEPT_LABELS) {
    if (new RegExp('\\b' + label.replace(/[.*+?^${}()|[\\]\\]/g, '\\$&') + '\\b').test(lower)) return false;
  }
  const palavras = t.split(/\s+/).filter(p => !PREPOSICOES.has(p.toLowerCase()));
  if (palavras.length < 1 || palavras.length > 4) return false;
  const caps = palavras.filter(p => p[0] === p[0].toUpperCase() && p[0] !== p[0].toLowerCase()).length;
  return caps >= Math.max(1, palavras.length - 1);
}

function isGenericLabel(texto) {
  if (!texto) return true;
  const clean = texto.replace(/[^\w\s]/g, '').trim().toLowerCase();
  if (!clean) return true;
  const words = new Set(clean.split(/\s+/));
  const allowed = new Set([...GENERIC_LABELS, ...PREPOSICOES]);
  for (const w of words) { if (!allowed.has(w)) return false; }
  return true;
}

function removeCityUf(texto) {
  const words = texto.split(/\s+/);
  if (words.length < 2) return texto;
  if (UFS.has(words[words.length - 1].toUpperCase())) {
    words.pop();
    if (words.length >= 2 && !ALL_COMPANY_WORDS.has(words[words.length - 1].toLowerCase())) {
      words.pop();
    }
  }
  while (words.length && PREPOSICOES.has(words[words.length - 1].toLowerCase())) words.pop();
  return words.join(' ');
}

function truncateAfterLastCompanyKeyword(texto) {
  if (!texto) return texto;
  const palavras = texto.split(/\s+/);
  let ultimaIdx = -1;
  for (let i = 0; i < palavras.length; i++) {
    const p = palavras[i].replace(/[.,;:]$/, '').toLowerCase();
    if (ALL_COMPANY_WORDS.has(p)) ultimaIdx = i;
  }
  if (ultimaIdx >= 0 && ultimaIdx < palavras.length - 1) {
    return palavras.slice(0, ultimaIdx + 1).join(' ');
  }
  return texto;
}

function titleCase(texto) {
  if (!texto) return '';
  return texto.split(/\s+/).map((p, i) => {
    const clean = p.replace(/[.,;:]+$/, '');
    const punct = p.slice(clean.length);
    if (clean === clean.toUpperCase() && clean.length >= 2 && clean.length <= 4) return clean + punct;
    if (clean === clean.toUpperCase() && clean.length === 1) return clean + punct;
    if (i > 0 && PREPOSICOES.has(clean.toLowerCase())) return clean.toLowerCase() + punct;
    return clean.charAt(0).toUpperCase() + clean.slice(1).toLowerCase() + punct;
  }).join(' ');
}

function extractParentheticalEmpresa(nome) {
  const m = nome.match(/^(.+?)\s*\((.+?)\)\s*$/);
  if (m) {
    const person = m[1].trim();
    const company = m[2].trim();
    if (hasCompanyKeyword(company)) return { person, company };
  }
  return null;
}

function extractDeptEmpresa(texto) {
  if (!texto) return null;
  const parts = texto.split(/\s*[-\u2013\u2014/]\s*/);
  if (parts.length >= 2) {
    const firstWords = new Set(extractWords(parts[0]));
    let hasDept = false;
    for (const w of firstWords) { if (DEPT_LABELS.has(w)) { hasDept = true; break; } }
    if (hasDept) {
      const rest = parts.slice(1).join(' ').trim();
      if (rest && hasCompanyKeyword(rest)) return rest;
      return null;
    }
    const lastWords = new Set(extractWords(parts[parts.length - 1]));
    let hasDeptLast = false;
    for (const w of lastWords) { if (DEPT_LABELS.has(w)) { hasDeptLast = true; break; } }
    if (hasDeptLast) {
      const rest = parts.slice(0, -1).join(' ').trim();
      if (rest && hasCompanyKeyword(rest)) return rest;
      return null;
    }
  }
  const allWords = new Set(extractWords(texto));
  let hasDeptWord = false;
  for (const w of allWords) { if (DEPT_LABELS.has(w)) { hasDeptWord = true; break; } }
  let hasCompanyWord = false;
  for (const w of allWords) { if (ALL_COMPANY_WORDS.has(w)) { hasCompanyWord = true; break; } }
  if (hasDeptWord && !hasCompanyWord) return null;
  if (texto.trim().startsWith('@')) return null;
  return texto;
}

function cleanEmpresaText(texto) {
  texto = normalizeSpacedUfs(texto);
  texto = cleanSeparators(texto);
  texto = removeCityUf(texto);
  texto = truncateAfterLastCompanyKeyword(texto);
  let words = texto.split(/\s+/);
  while (words.length && PREPOSICOES.has(words[words.length - 1].toLowerCase())) words.pop();
  return words.join(' ').trim();
}

function cleanNomeEmpresa(nome, empresa) {
  nome = (nome || '').trim();
  empresa = (empresa || '').trim();
  const acoes = [];

  nome = normalizeSpacedUfs(nome);
  empresa = normalizeSpacedUfs(empresa);

  if (nome && isPhoneInField(nome)) {
    acoes.push('P1:telefone_no_nome');
    nome = '';
  }

  if (nome && !empresa) {
    const p6 = extractParentheticalEmpresa(nome);
    if (p6) {
      nome = p6.person;
      empresa = p6.company;
      acoes.push('P6:parenteses');
    }
  }

  if (empresa) {
    const extracted = extractDeptEmpresa(empresa);
    if (extracted === null) {
      acoes.push('P5:label_descartado');
      empresa = '';
    } else if (extracted !== empresa) {
      acoes.push('P5:dept_extraido');
      empresa = extracted;
    }
  }

  if (empresa && nome && isPersonName(empresa) && isCompanyName(nome)) {
    const empLimpa = cleanEmpresaText(nome);
    nome = empresa;
    empresa = empLimpa;
    acoes.push('P4:inversao');
  } else if (empresa && !nome && isPersonName(empresa) && !hasCompanyKeyword(empresa)) {
    nome = empresa;
    empresa = '';
    acoes.push('P4b:pessoa_em_empresa');
  }

  if (nome && empresa && hasCompanyKeyword(nome) && hasCompanyKeyword(empresa)) {
    acoes.push('P3:empresa_duplicada');
    nome = '';
  }

  if (nome && !empresa && isCompanyName(nome)) {
    empresa = cleanEmpresaText(nome);
    acoes.push('P2:empresa_no_nome');
    nome = '';
  }

  if (nome) {
    nome = cleanSeparators(nome);
    const words = nome.split(/\s+/);
    if (words.length && UFS.has(words[words.length - 1].toUpperCase())) words.pop();
    nome = words.join(' ').trim();
  }

  if (empresa) {
    empresa = cleanSeparators(empresa).trim();
  }

  nome = titleCase(nome);
  empresa = titleCase(empresa);

  return { nome, empresa, acao: acoes.length ? acoes.join('; ') : 'nenhuma' };
}

function classifyLead(nome, empresa, whatsapp) {
  const phoneResult = normalizePhone(whatsapp);
  if (!phoneResult.valid) {
    return {
      status_validacao: 'INVALIDO_IRRECUPERAVEL',
      motivo_validacao: 'telefone_invalido',
      nome_limpo: '', empresa_limpa: '',
      whatsapp_limpo: phoneResult.phone,
      ddd: '', regiao: ''
    };
  }

  const cleaned = cleanNomeEmpresa(nome, empresa);

  if (!cleaned.nome && !cleaned.empresa) {
    return {
      status_validacao: 'INVALIDO_IRRECUPERAVEL',
      motivo_validacao: 'sem_identificacao',
      nome_limpo: '', empresa_limpa: '',
      whatsapp_limpo: phoneResult.phone,
      ddd: phoneResult.ddd, regiao: phoneResult.regiao
    };
  }

  if (isGenericLabel(cleaned.nome) && isGenericLabel(cleaned.empresa)) {
    return {
      status_validacao: 'INVALIDO_IRRECUPERAVEL',
      motivo_validacao: 'identificacao_generica',
      nome_limpo: cleaned.nome, empresa_limpa: cleaned.empresa,
      whatsapp_limpo: phoneResult.phone,
      ddd: phoneResult.ddd, regiao: phoneResult.regiao
    };
  }

  return {
    status_validacao: 'VALIDO',
    motivo_validacao: '',
    nome_limpo: cleaned.nome,
    empresa_limpa: cleaned.empresa,
    whatsapp_limpo: phoneResult.phone,
    ddd: phoneResult.ddd,
    regiao: phoneResult.regiao
  };
}

const phonesSeen = new Set();

return $input.all().map(item => {
  const d = item.json;
  const result = classifyLead(d.NOME || '', d.EMPRESA || '', d.WHATSAPP || '');

  if (result.status_validacao === 'VALIDO') {
    if (phonesSeen.has(result.whatsapp_limpo)) {
      result.status_validacao = 'REVISAR_MANUAL';
      result.motivo_validacao = 'telefone_duplicado';
    } else {
      phonesSeen.add(result.whatsapp_limpo);
    }
  }

  return {
    json: {
      ...d,
      status_validacao: result.status_validacao,
      motivo_validacao: result.motivo_validacao,
      nome_limpo: result.nome_limpo,
      empresa_limpa: result.empresa_limpa,
      whatsapp_limpo: result.whatsapp_limpo,
      ddd: result.ddd,
      regiao: result.regiao
    }
  };
});

// ═══════════════════════════════════════════════════════════════
// AGREGAR STATS — Gera relatorio da execucao
// ═══════════════════════════════════════════════════════════════

const allItems = [];
try { allItems.push(...$('ValidarLeads').all()); } catch(e) {}

const total = allItems.length;
let validos = 0, invalidos = 0, revisar = 0;
const motivos = {};

for (const item of allItems) {
  const status = item.json.status_validacao;
  if (status === 'VALIDO') validos++;
  else if (status === 'INVALIDO_IRRECUPERAVEL') invalidos++;
  else if (status === 'REVISAR_MANUAL') revisar++;

  const motivo = item.json.motivo_validacao;
  if (motivo) motivos[motivo] = (motivos[motivo] || 0) + 1;
}

const topMotivos = Object.entries(motivos)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([m, c]) => `${m}: ${c}`)
  .join(' | ');

const now = new Date().toISOString().replace('T', ' ').slice(0, 19);

return [{
  json: {
    TIMESTAMP: now,
    TOTAL_PROCESSADO: total,
    VALIDOS: validos,
    INVALIDOS: invalidos,
    REVISAR: revisar,
    TOP_MOTIVOS: topMotivos
  }
}];
